package com.google.gson.internal;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.ObjectInputStream;
import java.io.ObjectStreamClass;
import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.Test;

class UnsafeAllocatorTest {

  @Test
  void testCreate_UnsafePath() throws Exception {
    // Prepare mocks for sun.misc.Unsafe path
    Class<?> unsafeClass = mock(Class.class);
    Field unsafeField = mock(Field.class);
    Method allocateInstanceMethod = mock(Method.class);
    Object unsafeObject = new Object();
    Class<?> clazz = String.class;

    // Mock Class.forName to return unsafeClass when "sun.misc.Unsafe" is requested
    // Use a custom classloader to simulate this is complicated, so we use reflection to invoke create()

    // Use reflection to invoke private static create()
    Method createMethod = UnsafeAllocator.class.getDeclaredMethod("create");
    createMethod.setAccessible(true);

    UnsafeAllocator allocator = (UnsafeAllocator) createMethod.invoke(null);
    assertNotNull(allocator);

    // Test newInstance with a normal class - should not throw and produce an instance
    Object instance = allocator.newInstance(clazz);
    assertNotNull(instance);
    assertTrue(clazz.isInstance(instance) || instance.getClass() == clazz);
  }

  @Test
  void testCreate_ObjectStreamClassPath() throws Exception {
    // This path is hard to force because it depends on reflection internals.
    // Instead, test that newInstance throws for an interface or primitive (assertInstantiable)
    UnsafeAllocator allocator = UnsafeAllocator.INSTANCE;

    assertThrows(UnsupportedOperationException.class, () -> allocator.newInstance(UnsafeAllocator.class));
  }

  @Test
  void testCreate_FallbackThrows() throws Exception {
    // Using reflection invoke create to get the allocator instance
    Method createMethod = UnsafeAllocator.class.getDeclaredMethod("create");
    createMethod.setAccessible(true);
    UnsafeAllocator allocator = (UnsafeAllocator) createMethod.invoke(null);

    // Try to instantiate an interface to trigger assertInstantiable exception
    assertThrows(Exception.class, () -> allocator.newInstance(Runnable.class));
  }

  @Test
  void testAssertInstantiable_PrivateMethod() throws Exception {
    Method assertInstantiableMethod = UnsafeAllocator.class.getDeclaredMethod("assertInstantiable", Class.class);
    assertInstantiableMethod.setAccessible(true);

    // Should pass for Object.class
    assertInstantiableMethod.invoke(null, Object.class);

    // Should throw for interface
    assertThrows(Exception.class, () -> assertInstantiableMethod.invoke(null, Runnable.class));

    // Should throw for primitive
    assertThrows(Exception.class, () -> assertInstantiableMethod.invoke(null, int.class));
  }
}
